#!/usr/bin/env python3
"""
MKT Original Commentary — 2 Kings chapters 15 and 20 (fill: missed by prior scripts)
Run: python3 scripts/zc-original-2kings-fill-15-20.py

Ch 15: rapid-fire king succession in Israel (Azariah through Jotham in Judah);
       key: regnal and character formulae, tsara'at, Tiglath-Pileser III invasion
Ch 20: Hezekiah&#x2019;s illness and recovery; Babylonian envoys; Siloam tunnel;
       key: chalah mechalah, emeth, devela te&#x2019;enim, ma&#x2019;alot Ahaz, the ambiguous shalom response
"""

import json
from pathlib import Path

ROOT = Path(__file__).resolve().parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

TWO_KINGS = {
    "15": {
        "1": "<p>Azariah son of Amaziah becomes king of Judah in the twenty-seventh year of Jeroboam of Israel. The synchronism is one of the most precise in the Hebrew Bible, anchoring Judah&#x2019;s chronology to Israel&#x2019;s. The MKT renders the synchronistic formula literally to preserve its annalistic character.</p>",
        "2": "<p>Azariah&#x2019;s accession age of sixteen and fifty-two-year reign make him Judah&#x2019;s longest-reigning king after Manasseh. His mother Jecoliah is from Jerusalem — the narrative&#x2019;s note of Judahite lineage signals legitimacy.</p>",
        "3": "<p><em>wayyaʿaś hayyāšār bᵉʿênê YHWH kᵉkōl ʾăšer-ʿāśāh ʾĂmaṣyāhû ʾāḇîw ʿāśāh</em> — &#x201C;he did right in YHWH&#x2019;s eyes, according to all that his father Amaziah did.&#x201D; The character formula is positive but comparative: Azariah does right, but only as his father did — not the higher standard of David.</p>",
        "4": "<p><em>raq habbāmôṯ lōʾ-sārû</em> — &#x201C;only the high places were not removed.&#x201D; The standard caveat for otherwise faithful Judahite kings: cultic centralization at Jerusalem remained incomplete despite royal loyalty to YHWH. The high places were local worship sites, not necessarily idolatrous, but the Deuteronomic ideal demanded exclusive worship in Jerusalem.</p>",
        "5": "<p><em>wayyiggaʿ YHWH ʾeṯ-hammelek wayhî ṣārûaʿ ʿaḏ yôm môṯô</em> — &#x201C;the LORD struck the king so that he became a leper until the day of his death.&#x201D; <em>ṣārûaʿ</em> is the adjective from <em>ṣāraʿaṯ</em> (leprosy, scale disease) — the condition that required exclusion from the community (Lev 13). The cause of the affliction is unstated in Kings; 2 Chr 26:16-21 attributes it to Uzziah&#x2019;s unauthorized entry into the temple to burn incense. <em>bayiṯ haḥofšiṯ</em> (a separate/quarantine house) is a hapax legomenon — the MKT renders it &#x201C;a separate dwelling.&#x201D;</p>",
        "6": "<p>The reign-summary formula refers the reader to &#x201C;the book of the chronicles of the kings of Judah&#x201D; for Azariah&#x2019;s remaining acts. The phrase marks the annalistic source behind Kings; the Chronicler supplements it significantly (2 Chr 26) while Kings remains silent beyond the leprosy.</p>",
        "7": "<p>Azariah (Uzziah) sleeps with his fathers and is buried with them in the city of David — but the burial is qualified: 2 Chr 26:23 notes he was buried in the burial field of the kings because he was a leper, not in the tombs proper. Jotham his son succeeds him.</p>",
        "8": "<p>Zechariah son of Jeroboam II reigns six months over Israel — the last of Jehu&#x2019;s dynasty. The brevity signals dynastic collapse. The synchronism places his accession in Azariah&#x2019;s thirty-eighth year.</p>",
        "9": "<p><em>wayyaʿaś hāraʿ bᵉʿênê YHWH kᵃʾăšer ʿāśû ʾăḇōṯāyw</em> — &#x201C;he did evil in YHWH&#x2019;s eyes as his fathers did.&#x201D; The specific evil: <em>lōʾ-sār mēḥaṭṭôʾṯ Yārāḇᵉʿām</em> (he did not turn from the sins of Jeroboam) — the golden calves at Bethel and Dan, the defining sin of the northern kings from 1 Kings 12 onward.</p>",
        "10": "<p><em>wayyiqqāšer ʿālāyw Šallûm ben-Yāḇêš wayyakkēhû qāḇāl-ʿām wayyimittēhû wayyimlōk taḥtāyw</em> — &#x201C;Shallum son of Jabesh conspired against him, struck him down in Ibleam, and killed him.&#x201D; <em>qāḇāl-ʿām</em> is uncertain: the MKT follows the LXX reading &#x201C;before the people/publicly.&#x201D; Zechariah&#x2019;s assassination ends the Jehu dynasty after four generations.</p>",
        "11": "<p>The narrative notes that the rest of Zechariah&#x2019;s acts &#x201C;are written in the book of the chronicles of the kings of Israel&#x201D; — the annalistic formula closes even this brief reign properly.</p>",
        "12": "<p><em>hûʾ dᵉḇar-YHWH ʾăšer dibber ʾel-Yēhûʾ</em> — &#x201C;this was the word of the LORD which he spoke to Jehu.&#x201D; God had promised Jehu that four generations of his sons would sit on Israel&#x2019;s throne (2 Kgs 10:30). Zechariah is the fourth; his assassination closes the account. The narrator emphasizes the exact fulfillment of the prophetic word.</p>",
        "13": "<p>Shallum son of Jabesh reigns one month in Samaria — the shortest reign in Kings. He is immediately killed by Menahem son of Gadi. The rapid succession signals the accelerating collapse of the northern kingdom&#x2019;s political stability.</p>",
        "14": "<p><em>wayyaʿal Mᵉnaḥēm ben-Gāḏî miTTirṣāh wayyāḇōʾ Šōmᵉrônāh wayyak ʾeṯ-Šallûm ben-Yāḇêš</em> — &#x201C;Menahem son of Gadi went up from Tirzah and came to Samaria.&#x201D; Tirzah was the earlier Israelite capital (1 Kgs 15:33) — Menahem&#x2019;s base there suggests regional rather than dynastic authority. His seizure of power is violent and his rule will be marked by cruelty.</p>",
        "15": "<p>The formulaic reference to the chronicles of the kings of Israel follows Shallum&#x2019;s brief reign summary. The conspiracy note (<em>qešer ʾăšer qāšar</em>) repeats the assassination vocabulary, maintaining the literary pattern of regicide.</p>",
        "16": "<p><em>ʾāz yakkeh Mᵉnaḥēm ʾeṯ-Tipṣaḥ</em> — &#x201C;then Menahem struck Tiphsah.&#x201D; The city and its surrounding territory resisted, so Menahem destroys it. <em>wayᵉḇaqqaʿ ʾeṯ kol-haharôṯ bāh</em> — &#x201C;he ripped open all the pregnant women in it&#x201D; (<em>bāqaʿ</em> in its most brutal sense). This atrocity — applied elsewhere to Hazael (2 Kgs 8:12) and Amos&#x2019;s condemnation of Gilead (Amos 1:13) — establishes Menahem as a particularly brutal figure even in the context of ancient warfare.</p>",
        "17": "<p>Menahem son of Gadi begins to reign in the thirty-ninth year of Azariah of Judah and reigns ten years in Samaria. The synchronism continues the dual-kingdom chronological framework.</p>",
        "18": "<p>Menahem&#x2019;s character formula is the standard northern pattern: evil in YHWH&#x2019;s eyes, not turning from the calves of Jeroboam. The uniformity of these formulas across kings who differ in every other way emphasizes that the northern kingdom&#x2019;s fundamental sin is structural — embedded in its founding cult.</p>",
        "19": "<p><em>Pûl melek-ʾAššûr ʾāl ʿal-hāʾāreṣ wayyittēn Mᵉnaḥēm lᵉPûl ʾelep kikkār-kāsep</em> — &#x201C;Pul king of Assyria came against the land, and Menahem gave Pul a thousand talents of silver.&#x201D; Pul is the throne name of Tiglath-Pileser III in his Babylonian guise; Assyrian records confirm his campaigns against Israel. <em>lihyôṯ yāḏô ʾittô</em> — &#x201C;to have his hand with him&#x201D; — means to secure his support. A talent of silver was approximately 30 kg; a thousand talents was an enormous sum, signaling Israel&#x2019;s tributary status.</p>",
        "20": "<p><em>wayyōṣēʾ Mᵉnaḥēm ʾeṯ-hakkesep ʿal-Yiśrāʾēl ʿal kol-gibbôrê haḥayil</em> — &#x201C;Menahem exacted the silver from Israel, from all the men of means (<em>gibbôrê haḥayil</em>).&#x201D; <em>gibbôr hayil</em> typically means &#x201C;mighty warrior,&#x221D; but here the economic context gives it the sense &#x201C;man of substantial means/wealth.&#x201D; The MKT renders &#x201C;men of standing&#x201D; to capture both senses. Each man paid fifty shekels — a labor-tribute calculation.</p>",
        "21": "<p>Menahem sleeps with his fathers — a remarkable phrase given his brutality, but the formula is used regardless of character. His son Pekahiah succeeds him.</p>",
        "22": "<p>The formula closes Menahem&#x2019;s ten-year reign with the standard reference to the chronicles of the kings of Israel. His reign is notable as the first in which Assyrian tribute is paid — beginning Israel&#x2019;s final spiral.</p>",
        "23": "<p>Pekahiah son of Menahem begins to reign in Azariah&#x2019;s fiftieth year — the overlapping synchronisms reflect the complex chronological situation as Israel&#x2019;s kings multiply rapidly. His reign is two years.</p>",
        "24": "<p>Pekahiah receives the standard northern formula: evil in YHWH&#x2019;s eyes, not departing from the sins of Jeroboam. The formula&#x2019;s relentless repetition creates a rhetorical effect: each king is measured against the founding sin and found continuous with it.</p>",
        "25": "<p><em>wayyiqqāšer ʿālāyw Peqaḥ ben-Remalyāhû šālîšô</em> — &#x201C;Pekah son of Remaliah, his captain/officer, conspired against him.&#x201D; <em>šālîš</em> denotes a high military officer (the &#x201C;third man&#x22 in a chariot, hence officer). Pekah kills Pekahiah with fifty Gileadites in the citadel (<em>ʾarmon</em>) of the palace — a palace coup with military backing.</p>",
        "26": "<p>The reign summary for Pekahiah closes with the annalistic reference. His reign&#x2019;s brevity is noted without elaboration — the narrative pattern of rapid regicide continues.</p>",
        "27": "<p>Pekah son of Remaliah reigns twenty years over Israel — though the synchronism creates a chronological difficulty: his twenty-year reign in Azariah&#x2019;s fifty-second year does not align easily with the remaining years. The MKT preserves the text as received; critical scholars have proposed various solutions, including counting Pekah&#x2019;s years from a rival reign in Gilead.</p>",
        "28": "<p>Pekah receives the standard formula of northern evil. The consistency of character formula across all northern kings emphasizes the systemic character of the sin: it is not individual moral failure but structural unfaithfulness embedded in the Jeroboam cult.</p>",
        "29": "<p><em>bîmê Peqaḥ melek-Yiśrāʾēl bāʾ Tiglat Pilʾeser melek ʾAššûr wayyiqqaḥ ʾeṯ-ʿIyyôn</em> — &#x201C;in the days of Pekah king of Israel, Tiglath-Pileser king of Assyria came and took Ijon...Galilee, all the land of Naphtali.&#x201D; This verse records the beginning of the deportation — the first large-scale forced displacement of Israelite population to Assyria. The territories named — Galilee, Naphtali — are the ones Isaiah 9:1 will address: &#x201C;in the former time he brought into contempt the land of Zebulun and Naphtali, but in the latter time he has made glorious the way of the sea, the land beyond the Jordan, Galilee of the nations.&#x201D; The historical wound is the ground of the prophetic promise.</p>",
        "30": "<p><em>wayyiqqāšer Hôšēaʿ ben-ʾĒlāh ʿal-Peqaḥ ben-Remalyāhû wayyakkēhû wayyimittēhû</em> — &#x201C;Hoshea son of Elah conspired against Pekah son of Remaliah and struck him down and killed him.&#x201D; The regicide pattern continues: Pekah, who killed Pekahiah, is killed by Hoshea. Assyrian annals record that Tiglath-Pileser installed Hoshea as a vassal, suggesting Assyrian complicity in the assassination.</p>",
        "31": "<p>The reign summary for Pekah closes with the standard formula. His twenty-year reign has seen Israel reduced to a rump state, its northern territories depopulated and annexed to Assyria.</p>",
        "32": "<p>Jotham son of Uzziah (Azariah) begins to reign in Judah in Pekah&#x2019;s second year. The synchronism reconnects the dual narrative. Jotham is twenty-five and reigns sixteen years — a solid mid-length reign.</p>",
        "33": "<p>Jotham&#x2019;s maternal lineage: Jerusha daughter of Zadok — a Zadokite priestly family connection, strengthening his legitimacy credentials in the Deuteronomic framework.</p>",
        "34": "<p><em>wayyaʿaś hayyāšār bᵉʿênê YHWH kᵉkōl ʾăšer-ʿāśāh ʿUzziyyāhû ʾāḇîw ʿāśāh</em> — &#x201C;he did right in YHWH&#x2019;s eyes according to all that his father Uzziah did.&#x201D; The comparison is to Uzziah/Azariah — itself a comparative (not Davidic) standard. The qualified approval continues the pattern.</p>",
        "35": "<p><em>raq habbāmôṯ lōʾ-sārû</em> — the high-places caveat. Jotham also built the upper gate of the house of the LORD (<em>šaʿar-bayiṯ YHWH hāʿelyôn</em>). This temple building activity is a point of distinction — the Chronicler expands on Jotham&#x2019;s building programs (2 Chr 27:3-4), establishing him as a legitimate king who maintains the temple.</p>",
        "36": "<p>The reign summary refers to the chronicles of the kings of Judah. The Chronicler (2 Chr 27) supplements this with building in the hill country of Judah and military campaigns against the Ammonites.</p>",
        "37": "<p><em>bāyyāmîm hāhēm hēḥēl YHWH lᵉšallēaḥ bîhûḏāh ʾeṯ-Rᵉṣîn melek-ʾĂram wᵉʾeṯ Peqaḥ ben-Remalyāhû</em> — &#x201C;in those days the LORD began to send Rezin king of Aram and Pekah son of Remaliah against Judah.&#x201D; The verb <em>hēḥēl</em> (began) is significant: God initiates the Syro-Ephraimite pressure. This sets up the crisis addressed in Isaiah 7-9 — the Syro-Ephraimite war that provides the context for the Immanuel and Maher-shalal-hash-baz prophecies.</p>",
        "38": "<p>Jotham sleeps with his fathers and is buried in the city of David. His son Ahaz succeeds him. The transition sets up one of the most fraught reigns in Judah&#x2019;s history — Ahaz&#x2019;s faithless response to the Syro-Ephraimite threat and his appeal to Assyria (2 Kgs 16; Isa 7).</p>"
    },
    "20": {
        "1": "<p><em>bāyyāmîm hāhēm ḥālāh Ḥizqiyyāhû lāmûṯ</em> — &#x201C;in those days Hezekiah became ill to the point of death.&#x201D; The infinitive construct <em>lāmûṯ</em> (&#x201C;to die&#x201D;) attached to <em>ḥālāh</em> (ill) creates a phrase of medical finality. Isaiah son of Amoz comes to Hezekiah with a divine oracle: <em>ṣaw lᵉḇêṯekā kî mēṯ ʾattāh wᵉlōʾ tiḥyeh</em> — &#x201C;put your house in order, for you are dying and will not live.&#x201D;</p>",
        "2": "<p><em>wayyāsob ʾeṯ-pānāyw ʾel-haqqîr wayyiṯpallēl</em> — &#x201C;he turned his face to the wall and prayed to the LORD.&#x201D; The physical gesture — turning toward the wall, away from the people — marks private, urgent petition. <em>hitpallēl</em> (reflexive of <em>pallel</em>) means to intercede, pray — the standard term for intercessory and petitionary prayer.</p>",
        "3": "<p><em>ʾānnāh YHWH zᵉḵor-nāʾ ʾēṯ ʾăšer hiṯhallakṯî lᵉfānekā bᵉʾĕmeṯ ûḇᵉlēḇāḇ šālēm</em> — &#x201C;Please, LORD, remember how I have walked before you in faithfulness (<em>ʾĕmeṯ</em>) and with a whole heart (<em>lēḇāḇ šālēm</em>).&#x201D; <em>ʾĕmeṯ</em> is reliability, faithfulness, covenant truth. <em>lēḇāḇ šālēm</em> (whole/complete heart) is the Deuteronomic ideal of undivided loyalty to YHWH. Hezekiah appeals to his own covenant fidelity as the basis for divine compassion — not presumption but covenant confidence.</p>",
        "4": "<p>Before Isaiah had left the middle court (<em>haḥāṣēr hattîḵônāh</em>), the word of the LORD came to him. The physical immediacy — the prophet has barely departed the sick king&#x2019;s chamber — emphasizes the speed of divine response. YHWH hears and responds before the petition has fully been voiced.</p>",
        "5": "<p><em>šūḇ wᵉʾāmarṯā ʾel-Ḥizqiyyāhû nāḡîḏ-ʿammî</em> — &#x201C;return and say to Hezekiah the leader of my people.&#x201D; <em>nāḡîḏ</em> (leader, designated ruler) is used here rather than <em>melek</em> (king) — a title emphasizing Hezekiah&#x2019;s role as YHWH&#x2019;s appointed steward. The divine promise: <em>rāpāʾ ʾᵉrāpāʾ leḵā</em> — &#x201C;I will surely heal you&#x201D; (infinitive absolute for emphasis). On the third day Hezekiah will go up to the house of the LORD.</p>",
        "6": "<p>God adds fifteen years to Hezekiah&#x2019;s life and promises to deliver Jerusalem from the hand of the king of Assyria. The Assyrian threat (Sennacherib&#x2019;s 701 BCE campaign) and the personal illness are both addressed in a single divine act of salvation. <em>wᵉgannōṯî ʿal-hāʿîr hazzōʾṯ</em> — &#x201C;and I will defend this city&#x201D; — uses the same language as 2 Kgs 19:34.</p>",
        "7": "<p><em>ûqᵉḥû ḏᵉḇeleth tᵉʾēnîm</em> — &#x201C;take a cake of figs (<em>dᵉḇeleth tᵉʾēnîm</em>).&#x201D; <em>dᵉḇelah</em> is a pressed fig cake — figs were used in ancient Near Eastern medicine as poultices. Isaiah prescribes the medical treatment at the divine command, blending prophetic oracle and medical instruction. The poultice (<em>wayyāśîmû ʿal-haššᵉḥîn</em> — placed on the boil/inflammation) would have had both symbolic and medicinal function.</p>",
        "8": "<p>Hezekiah asks for a sign that YHWH will heal him and that he will go up to the temple on the third day. The request for a sign (<em>ʾôṯ</em>) is not unbelief but covenant expectation: YHWH has historically confirmed his promises with signs (cf. Isa 7:11-14). The sign-request follows the pattern of Gideon (Judg 6:17) and Moses (Exod 4:1-9).</p>",
        "9": "<p><em>yēlek haṣṣēl ʿeśer maʿălôṯ ʾim-yāšûḇ ʿeśer maʿălôṯ</em> — &#x201C;shall the shadow go forward ten steps, or shall it go back ten steps?&#x201D; <em>maʿălôṯ</em> is the word for &#x201C;steps&#x221D; or &#x201C;degrees&#x221D; — the same word used in the Psalms of Ascent (<em>šîr hammaʿălôṯ</em>). The sign involves the shadow on the steps of Ahaz (<em>maʿălôṯ ʾĀḥāz</em>) — a sundial-like device.</p>",
        "10": "<p>Hezekiah chooses the harder sign: the shadow going backward rather than forward. <em>wᵉqālel laṣṣēl linṭôṯ ʿeśer maʿălôṯ</em> — &#x201C;it is an easy thing for the shadow to lengthen ten steps.&#x201D; The reversal of the shadow&#x2019;s direction requires a more dramatic divine intervention. The MKT preserves &#x201C;steps/degrees&#x221D; throughout to maintain the ambiguity of whether this was a literal sundial or a monumental staircase.</p>",
        "11": "<p><em>wayyiqrāʾ Yᵉšaʿyāhû hannāḇîʾ ʾel-YHWH wayyāšeḇ ʾeṯ-haṣṣēl bamaʿălôṯ ʾăšer yārᵉḏāh bᵉmaʿălôṯ ʾāḥāz ʾăḥôrannîṯ ʿeśer maʿălôṯ</em> — &#x201C;and Isaiah the prophet called to the LORD, and he brought the shadow back the ten steps by which it had gone down on the steps of Ahaz.&#x201D; The reversal of shadow confirms the reversal of divine decree against Hezekiah. <em>ʾăḥôrannîṯ</em> (backward) is the emphatic form marking the miraculous direction.</p>",
        "12": "<p><em>bāʿēṯ hahîʾ šālaḥ Bᵉrōʾḏak-Balʾadān ben-Balʾadān melek-Bāḇel sᵉpārîm ûminḥāh ʾel-Ḥizqiyyāhû</em> — &#x201C;at that time Merodach-Baladan son of Baladan king of Babylon sent letters and a gift to Hezekiah.&#x201D; Merodach-Baladan (Marduk-apla-iddina II) is documented in Assyrian records as a Chaldean king who ruled Babylon intermittently and resisted Assyrian hegemony. His embassy to Hezekiah is politically motivated: both resist Assyria. The gift (<em>minḥāh</em>) establishes a diplomatic relationship.</p>",
        "13": "<p><em>wayyišmaʿ ʿălêhem Ḥizqiyyāhû wayyarʾēm ʾeṯ kol-bayiṯ nᵉḵōṯōh</em> — &#x201C;and Hezekiah listened to them and showed them all his storehouse (<em>bayiṯ nᵉḵōṯōh</em>).&#x201D; <em>nᵉḵōṯ</em> is an unusual term for treasure/precious things. Hezekiah&#x2019;s display of all his wealth — silver, gold, spices, fine oil, armory, everything in his treasuries — is presented without editorial comment but the subsequent prophetic condemnation makes clear it was imprudent. The pride of display sets up Isaiah&#x2019;s oracle.</p>",
        "14": "<p><em>wayyāḇōʾ Yᵉšaʿyāhû hannāḇîʾ ʾel-hammelek Ḥizqiyyāhû wayyōʾmer ʾēlāyw mah ʾāmᵉrû hāʾănāšîm hāʾēlleh</em> — &#x201C;then Isaiah the prophet came to King Hezekiah and asked him: What did these men say?&#x201D; The prophetic interrogation technique: drawing out the confession before delivering the judgment. Hezekiah answers candidly: they came from Babylon.</p>",
        "15": "<p><em>ûmāh rāʾû bᵉḇêṯekā</em> — &#x201C;what have they seen in your house?&#x201D; Hezekiah&#x2019;s answer is complete and self-incriminating: <em>ʾēṯ kol-ʾăšer bᵉḇêṯî rāʾû lōʾ-hāyāh ḏāḇār ʾăšer lōʾ-hᵉrʾîṯîm bᵉʾôṣᵉrōṯāy</em> — &#x201C;they saw everything in my house; there was nothing in my treasuries that I did not show them.&#x201D; The comprehensive disclosure becomes the grounds for comprehensive dispossession.</p>",
        "16": "<p><em>wayyōʾmer Yᵉšaʿyāhû ʾel-Ḥizqiyyāhû šᵉmaʿ dᵉḇar-YHWH</em> — &#x201C;then Isaiah said to Hezekiah: Hear the word of the LORD.&#x201D; The prophetic hearing formula introduces the judgment oracle. Everything Hezekiah showed the Babylonians will go to Babylon; nothing will remain.</p>",
        "17": "<p><em>hinnēh yāmîm bāʾîm wᵉniśśāʾ kol ʾăšer bᵉḇêṯekā</em> — &#x201C;behold, days are coming when everything in your house will be carried off.&#x201D; The oracle is precisely calibrated to the offense: Hezekiah showed them his wealth; YHWH announces it will be taken. <em>wᵉkol ʾăšer ʾāṣᵉrû ʾăḇōṯekā ʿaḏ-hayyôm hazzeh Bāḇelāh yûḇāʾ</em> — &#x201C;everything your fathers stored up until this day will be carried to Babylon.&#x201D;</p>",
        "18": "<p><em>ûmibbānêkā ʾăšer yēṣᵉʾû mimmᵉkā</em> — &#x201C;and some of your sons who will descend from you...will be taken away; and they will become eunuchs (<em>sārîsîm</em>) in the palace of the king of Babylon.&#x201D; The oracle extends the judgment to Hezekiah&#x2019;s descendants. <em>sārîs</em> (eunuch/court officer) here likely means both; Daniel and his companions may be the fulfillment the narrative points toward (Dan 1:3-7).</p>",
        "19": "<p><em>wayyōʾmer Ḥizqiyyāhû ʾel-Yᵉšaʿyāhû ṭôḇ dᵉḇar-YHWH ʾăšer dibbarṯā</em> — &#x201C;Hezekiah said to Isaiah: The word of the LORD that you have spoken is good.&#x201D; His follow-up is disputed: <em>hălōʾ ʾim-šālôm weʾĕmeṯ yihyeh bᵉyāmāy</em> — &#x201C;will there not be peace and truth in my days?&#x201D; Some read this as grateful submission (the calamity is deferred); others read it as self-centered acceptance (as long as peace lasts during my reign). The ambiguity is deliberate: the narrative declines to exonerate or condemn. The MKT renders <em>šālôm weʾĕmeṯ</em> as &#x201C;peace and stability&#x201D; to preserve the colloquial pair.</p>",
        "20": "<p><em>wᵉyeter diḇrê Ḥizqiyyāhû wᵉkol-gᵉḇûrāṯô wᵉʾăšer ʿāśāh ʾeṯ-haḇᵉrêḵāh wᵉʾeṯ-hattᵉʿālāh</em> — &#x201C;the rest of Hezekiah&#x2019;s acts and all his might and how he made the pool and the conduit (<em>hattᵉʿālāh</em>).&#x201D; <em>tᵉʿālāh</em> is the water channel; this refers to the Siloam tunnel, hewn through 533 meters of solid rock by Hezekiah&#x2019;s engineers to bring water from the Gihon Spring into the city during the Assyrian siege. The Siloam Inscription (discovered 1880) describes the tunneling from both ends meeting in the middle — a remarkable engineering feat confirmed by archaeology.</p>",
        "21": "<p>Hezekiah sleeps with his fathers after a reign of twenty-nine years (cf. 2 Kgs 18:2). His son Manasseh succeeds him — the transition is stark: Judah&#x2019;s most faithful king is succeeded by its most wicked. The contrast between Hezekiah (who sought YHWH) and Manasseh (who will undo everything Hezekiah reformed) frames the final decades of Judah&#x2019;s existence as a kingdom.</p>"
    }
}

def main():
    existing = load_comm('mkt-original', '2kings')
    merge_comm(existing, TWO_KINGS)
    save_comm('mkt-original', '2kings', existing)
    print('2 Kings original chapters 15 and 20 written.')

if __name__ == '__main__':
    main()
